idx = 0
t = int(input_data[idx]); idx+=1
for _ in range(t):
    n, m = int(input_data[idx]), int(input_data[idx+1]); idx+=2
    grid = []
    lab = (0,0)
    for i in range(n):
        row = input_data[idx].decode(); idx+=1
        grid.append(list(row))
        if 'L' in row:
            lab = (i, row.index('L'))
    dirs = [(-1,0),(1,0),(0,-1),(0,1)]
    k = [[0]*m for _ in range(n)]
    for i in range(n):
        for j in range(m):
            if grid[i][j] != '#':
                for di,dj in dirs:
                    ni,nj=i+di,j+dj
                    if 0<=ni<n and 0<=nj<m and grid[ni][nj]!='#':
                        k[i][j]+=1
    bad = [row[:] for row in k]
    good = [[False]*m for _ in range(n)]
    q = deque()
    li,lj = lab
    good[li][lj]=True
    q.append((li,lj))
    while q:
        r,c = q.popleft()
        for di,dj in dirs:
            nr,nc=r+di,c+dj
            if 0<=nr<n and 0<=nc<m and grid[nr][nc]!='#' and not good[nr][nc]:
                bad[nr][nc]-=1
                kv=k[nr][nc]; bv=bad[nr][nc]
                if bv<=1 and kv>=bv+1:
                    good[nr][nc]=True
                    q.append((nr,nc))
    for i in range(n):
        for j in range(m):
            if good[i][j] and grid[i][j]=='.':
                grid[i][j]='+'
    print('\n'.join(''.join(r) for r in grid))

